const chatIds = [
  "7578428511",
  "7237174388",
  "7867904883", 
  "1547297287"

];

const tiempoString = $input.first().json['Readable time'];

function parsearHora(horaStr) {
  const partes = horaStr.match(/(\d+):(\d+):(\d+)\s*(am|pm)/i);

  if (!partes) return null;

  let horas = parseInt(partes[1]);
  const minutos = parseInt(partes[2]);
  const segundos = parseInt(partes[3]);
  const ampm = partes[4].toLowerCase();

  if (ampm === 'pm' && horas < 12) {
    horas += 12;
  } else if (ampm === 'am' && horas === 12) {
    horas = 0;
  }

  return { horas, minutos, segundos };
}

function calcularDiferenciaCon630(horaStr) {
  const horaActual = parsearHora(horaStr);

  if (!horaActual) {
    return {
      texto: "Error: Formato de hora no válido",
      minutosDiferencia: 0,
      horasDiferencia: 0
    };
  }

  const minutosActuales = (horaActual.horas * 60) + horaActual.minutos;
  const minutos630 = (6 * 60) + 30;

  const diferenciaMinutos = minutosActuales - minutos630;
  const horas = Math.floor(Math.abs(diferenciaMinutos) / 60);
  const minutos = Math.abs(diferenciaMinutos) % 60;

  let signo = "";
  if (diferenciaMinutos > 0) {
    signo = "después";
  } else if (diferenciaMinutos < 0) {
    signo = "antes";
  } else {
    signo = "exactamente";
  }

  let texto;
  if (diferenciaMinutos === 0) {
    texto = "exactamente las 6:30";
  } else if (horas === 0) {
    texto = `${minutos} minutos ${signo} de las 6:30`;
  } else {
    texto = `${horas} horas y ${minutos} minutos ${signo} de las 6:30`;
  }

  return {
    texto: texto,
    minutosDiferencia: diferenciaMinutos,
    horasDiferencia: horas
  };
}

const resultado = calcularDiferenciaCon630(tiempoString);

// Aquí asignamos un nombre temporal que luego será reemplazado
// por el nombre real cuando pase por Telegram
return chatIds.map(id => ({
  json: {
    chatId: id,
    nombreTemp: "Cargando...", // Este será reemplazado
    horaActual: tiempoString,
    diferencia: resultado.texto,
    minutosDiferencia: resultado.minutosDiferencia,
    horasDiferencia: resultado.horasDiferencia
  }
}));

// Obtener todos los items de entrada
const items = $input.all();

// Procesar cada item para extraer el nombre y la interacción
const resultados = items.map(item => {
  // Extraer nombre del usuario
  const nombre = item.json?.result?.chat?.first_name || 
                item.json?.from?.first_name || 
                item.json?.chat?.first_name || 
                "Nombre no disponible";

  const chatId = item.json?.result?.chat?.id || 
                item.json?.chat?.id || 
                item.json?.chatId;

  const horaActual = item.json?.horaActual || 
                    item.json?.result?.text?.match(/Hora: (.*?)(?:\n|$)/)?.[1] || 
                    "Hora no disponible";

  // Extraer la diferencia del texto del mensaje
  let diferencia = item.json?.diferencia;
  if (!diferencia && item.json?.result?.text) {
    const match = item.json.result.text.match(/Queda (.*?) para completar/);
    diferencia = match ? match[1] : "No disponible";
  }

  // Capturar la interacción del usuario (qué botón oprimió)
  let interaccion = "Sin interacción";

  // Verificar si hay callback_query (cuando el usuario hace clic en un botón inline)
  if (item.json?.callback_query?.data) {
    interaccion = item.json.callback_query.data;
  } 
  // Verificar si hay mensaje de texto de respuesta
  else if (item.json?.message?.text) {
    interaccion = item.json.message.text;
  }
  // Verificar si hay texto en el resultado
  else if (item.json?.result?.text) {
    interaccion = item.json.result.text;
  }
  // Verificar si es el mensaje enviado por el bot (sin interacción aún)
  else if (item.json?.text) {
    interaccion = "Mensaje enviado - Esperando respuesta";
  }

  // Detectar específicamente qué botón se oprimió
  if (interaccion.includes("Ok, Vuelve a Ingresar Mañana")) {
    interaccion = "Botón: Ya realicé el reporte";
  } else if (item.json?.callback_query?.data === "Ingresar al Formulario" || 
             interaccion.includes("Ingresar al Formulario")) {
    interaccion = "Botón: Ingresar al Formulario";
  }

  return {
    json: {
      chatId: chatId,
      nombreCompleto: `${nombre} ${item.json?.result?.chat?.last_name || ''}`.trim(),
      nombre: nombre,
      apellido: item.json?.result?.chat?.last_name || '',
      horaActual: horaActual,
      diferencia: diferencia,
      minutosDiferencia: item.json?.minutosDiferencia || 0,
      horasDiferencia: item.json?.horasDiferencia || 0,
      interaccion: interaccion,
      timestamp: new Date().toISOString()
    }
  };
});

return resultados;
